    in_array('wishlist_page', (array) $this->config->get('module_ps_quantity_increment_decrement_show_on_page'))
);

$this->load->language('extension/module/ps_quantity_increment_decrement', 'ps_quantity_increment_decrement');

$ps_language = $this->language->get('ps_quantity_increment_decrement');

$data['ps_button_increment'] = $ps_language->get('button_increment');
$data['ps_button_decrement'] = $ps_language->get('button_decrement');

$data['ps_base_theme'] = $this->config->get('module_ps_quantity_increment_decrement_base_theme');
