$data['ps_text_align'] = $this->config->get('module_ps_quantity_increment_decrement_text_align');

$ps_icons = $this->ps_quantity_increment_decrement->getButtonIconClasses($this->config->get('module_ps_quantity_increment_decrement_btn_icon'));

$data['ps_increment_icon'] = $ps_icons['increment'];
$data['ps_decrement_icon'] = $ps_icons['decrement'];

$data['ps_btn_color'] = $this->config->get('module_ps_quantity_increment_decrement_btn_color');
$data['ps_btn_bg_start'] = $this->config->get('module_ps_quantity_increment_decrement_btn_bg_start');
$data['ps_btn_bg_end'] = $this->config->get('module_ps_quantity_increment_decrement_btn_bg_end');
$data['ps_btn_border_color_all'] = $this->config->get('module_ps_quantity_increment_decrement_btn_border_color_all');
$data['ps_btn_border_color_bottom'] = $this->config->get('module_ps_quantity_increment_decrement_btn_border_color_bottom');
$data['ps_btn_hover_bg'] = $this->config->get('module_ps_quantity_increment_decrement_btn_hover_bg');
$data['ps_btn_active_bg'] = $this->config->get('module_ps_quantity_increment_decrement_btn_active_bg');
